const outputCollection = [];

for (const item of $input.all()) {
  try {
    const blueprint = item.json.messages && item.json.messages[0] && item.json.messages[0].data;
    if (!blueprint) continue;

    const sku = item.json.sessionId ? item.json.sessionId.split('-').slice(1).join('-') : (blueprint.service_sku || "N/D");
    const bpName = blueprint.blueprint_name || "Protocollo Senza Nome";

    const controlliMitigazione = [];

    // --- AGGIUNTA CHIRURGICA 1: Preparo i contenitori per operatori e attrezzature ---
    const setOperatori = new Set();
    const setAttrezzature = new Set();

    // Estrae solo gli step con controllo di qualità obbligatorio (la mitigazione)
    if (blueprint.stages && Array.isArray(blueprint.stages)) {
      blueprint.stages.forEach(stage => {

        // Estraiamo il parametro di cadenza della fase (se non definito, di default è 0)
        const schedulingInterval = (stage.scheduling_interval_days !== undefined) ? stage.scheduling_interval_days : 0;

        if (stage.steps && Array.isArray(stage.steps)) {
          stage.steps.forEach(step => {

            // --- AGGIUNTA CHIRURGICA 2: Pesca risorse da ogni step ---
            if (step.resources_needed) {
                if (step.resources_needed.labor && step.resources_needed.labor.required_skill_tags) {
                    step.resources_needed.labor.required_skill_tags.forEach(op => setOperatori.add(op));
                }
                if (step.resources_needed.assets && Array.isArray(step.resources_needed.assets)) {
                    step.resources_needed.assets.forEach(ass => setAttrezzature.add(ass));
                }
                if (step.resources_needed.materials && Array.isArray(step.resources_needed.materials)) {
                    step.resources_needed.materials.forEach(mat => {
                        if (typeof mat === 'string') setAttrezzature.add(mat);
                        else if (mat.material_sku) setAttrezzature.add(mat.material_sku.replace('MAT_', '').replace(/_/g, ' '));
                    });
                }
            }
            // ---------------------------------------------------------

            if (step.quality_check && step.quality_check.is_required) {

              // Estrae i ruoli responsabili dello step
              let operatori = [];
              if (step.resources_needed && step.resources_needed.labor && step.resources_needed.labor.required_skill_tags) {
                operatori = step.resources_needed.labor.required_skill_tags;
              }

              // Inserisce le informazioni di mitigazione essenziali
              controlliMitigazione.push({
                fase_operativa: step.step_name,
                operatore_responsabile: operatori.join(", "),

                // Check di mitigazione prestabilito
                check_prestabilito: step.quality_check.check_description,
                criterio_accettazione: step.quality_check.acceptance_criteria,
                tipo_evidenza: step.quality_check.evidence_type,

                // --- INIEZIONE PARAMETRO DI PIANIFICAZIONE RICHIESTO ---
                scheduling_interval_days: schedulingInterval // Es. 0, 7, 14, 21, 180
              });
            }
          });
        }
      });
    }

    // Crea il record strutturato con SKU e Nome divisi
    if (controlliMitigazione.length > 0) {
      outputCollection.push({
        json: {
          service_sku: sku,
          service_name: bpName,
          // --- AGGIUNTA CHIRURGICA 3: Le chiavi finiscono dentro il json dell'oggetto ---
          operatori_coinvolti: Array.from(setOperatori),
          attrezzature_coinvolte: Array.from(setAttrezzature),
          controlli_mitigazione: controlliMitigazione
        }
      });
    }

  } catch (error) {
    outputCollection.push({
      json: {
        status: "ERROR",
        message: "Errore durante l'estrazione dei controlli",
        details: error.message
      }
    });
  }
}

return outputCollection;

const catalogActiveArray = [];

for (const item of $input.all()) {
  try {
    const catalog = item.json.service_catalog;
    if (!catalog || !catalog.categories) continue;

    catalog.categories.forEach(category => {
      // Normalizzazione della macrocategoria
      let macro = (category.macrocategories || "").toUpperCase().trim();

      if (!macro) {
        const catName = (category.name || "").toUpperCase();
        if (catName.includes("[SOP]")) macro = "SOP";
        else if (catName.includes("[SER]")) macro = "SER";
        else if (catName.includes("[PRO]")) macro = "PRO";
      }

      // 1. Elimina le PRO
      if (macro === "PRO") {
        return; 
      }

      if (category.subcategories && Array.isArray(category.subcategories)) {
        category.subcategories.forEach(sub => {
          const flatItem = {
            service_sku: sub.callback_data,
            service_name: sub.name,
            categoria_padre: category.name,
            short_name: sub.short_name || sub.name,
            vertical: category.vertical || "common",
            blueprint_ready: sub.blueprint_ready || "false"
          };

          // 2. Se è SOP passa sempre
          if (macro === "SOP") {
            catalogActiveArray.push(flatItem);
          }
          // 3. Se è SER passa solo se attiva (blueprint_ready === true)
          else if (macro === "SER") {
            if (sub.blueprint_ready === true) {
              catalogActiveArray.push(flatItem);
            }
          }
        });
      }
    });

  } catch (error) {
    return [{ 
      json: { 
        status: "ERROR", 
        message: "Errore durante l'elaborazione del catalogo", 
        details: error.message 
      } 
    }];
  }
}

// Restituisce l'array piatto originale con i dati corretti
return [{ json: { catalog_active: catalogActiveArray } }];

const items = $input.all();
const output = [];

for (const item of items) {
    const body = item.json.body || {};
    const sku = body.service_sku;

    if (!sku) continue; 

    // 1. Recupera lo stato storico dal DB
    let existingData = item.json.risk || item.json.checklist_state || [];

    // Se per caso era il vecchio formato "Oggetto", lo convertiamo in Array al volo
    if (!Array.isArray(existingData)) {
        delete existingData.additional_kwargs;
        delete existingData.response_metadata;

        let tempArray = [];
        for (let key in existingData) {
            let obj = existingData[key];
            if (typeof obj === 'object') {
                obj.service_sku = key; // Salviamo la chiave come valore!
                tempArray.push(obj);
            }
        }
        existingData = tempArray;
    }

    // Facciamo una Copia Profonda dell'Array
    let checklistArray = JSON.parse(JSON.stringify(existingData));

    // 2. Costruisce il nuovo Record (Includendo i parametri temporali del frontend)
    const updatedRecord = {
        service_sku: sku, // SKU memorizzato come valore interno al record
        service_name: body.service_name || "",
        service_category: body.service_category || "",
        service_description: body.service_description || "",
        risk_warnings: body.risk_warnings || [],

        // --- RECUPERO E PERSISTENZA CADENZA TEMPORALE E STORICA ---
        scheduling_interval: body.scheduling_interval !== undefined ? body.scheduling_interval : 0,
        last_executed: body.last_executed || null, // <--- SALVATAGGIO ULTIMA DATA DI ESECUZIONE

        starting_damage: body.starting_damage || 2,
        starting_contamination: body.starting_contamination || 1,
        starting_risk: body.starting_risk || 8,

        D: body.current_damage || 2,
        C: body.current_contamination || 1,
        P: body.current_probability || 4,
        R: body.current_risk || 8,
        overall_justification: body.current_justification || "",

        answers: body.checklist_state || {}
    };

    // 3. UPSERT NELL'ARRAY: Cerca se lo SKU esiste già. Se c'è lo sovrascrive, sennò lo aggiunge.
    let foundIndex = checklistArray.findIndex(el => 
        (el.service_sku && el.service_sku.toUpperCase() === sku.toUpperCase())
    );

    if (foundIndex >= 0) {
        checklistArray[foundIndex] = updatedRecord; // Aggiorna
    } else {
        checklistArray.push(updatedRecord); // Aggiunge nuovo
    }

    // 4. Recupera Partita IVA
    let vat = item.json.owner_data?.vat_number || item.json.vat_number || body.vat_number;

    // 5. Spedisce l'ARRAY aggiornato al DB
    output.push({
        json: {
            vat_number: vat,
            checklist_state: checklistArray 
        }
    });
}

return output;

const items = $input.all();
const sanitizedOutput = [];

for (const item of items) {
    // 1. Inizializziamo un nuovo oggetto vuoto per copiare solo i campi strettamente necessari
    const original = item.json;
    const safeData = {};

    // 2. catalog_active: Mantiene solo lo SKU, nome, categoria, sezioni, e stato di attivazione
    if (Array.isArray(original.catalog_active)) {
        safeData.catalog_active = original.catalog_active.map(cat => {
            if (!cat) return null;
            return {
                service_sku: cat.service_sku,
                service_name: cat.service_name,
                categoria_padre: cat.categoria_padre,
                short_name: cat.short_name || cat.service_name,
                vertical: cat.vertical || 'common',
                blueprint_ready: cat.blueprint_ready === true || cat.blueprint_ready === 'true',
                days: cat.days,
                scheduling_interval: cat.scheduling_interval
            };
        }).filter(Boolean);
    } else {
        safeData.catalog_active = [];
    }

    // 3. Product_Reserch (Dossier): Conserva solo il MODULE_4 (sicurezza e leggi) per ogni dossier, scartando i moduli 1-2-3-5-6-7-8
    if (Array.isArray(original.Product_Reserch)) {
        safeData.Product_Reserch = original.Product_Reserch.map(pr => {
            if (!pr) return null;
            const cleanPR = {
                session_id: pr.session_id
            };
            if (pr.dossier && pr.dossier.MODULE_4_PRODUCT_SERVICE_COMPLIANCE) {
                cleanPR.dossier = {
                    MODULE_4_PRODUCT_SERVICE_COMPLIANCE: pr.dossier.MODULE_4_PRODUCT_SERVICE_COMPLIANCE
                };
            }
            return cleanPR;
        }).filter(Boolean);
    } else {
        safeData.Product_Reserch = [];
    }

    // 4. owner_data: Mantiene solo l'anagrafica base per intestazioni e i metadati RSPP/RLS. Scarta salari, dipendenti e chiavi API.
    if (original.owner_data) {
        const od = original.owner_data;
        safeData.owner_data = {
            ragione_sociale: od.ragione_sociale || od.name || '',
            name: od.name || od.ragione_sociale || '',
            vat_number: od.vat_number || od.p_iva || '',
            p_iva: od.p_iva || od.vat_number || '',
            indirizzo: od.indirizzo || od.address || '',
            address: od.address || od.indirizzo || '',
            verticals: od.verticals || [],
            activeVerticals: od.activeVerticals || od.active_verticals || od.verticals || [],
            active_verticals: od.active_verticals || od.activeVerticals || od.verticals || [],
            assessments: od.assessments || [],
            securityMetadata: od.securityMetadata || od.security_metadata || od.generalMetadata || od.general_metadata || {},
            security_metadata: od.security_metadata || od.securityMetadata || od.general_metadata || od.generalMetadata || {}
        };
    } else {
        safeData.owner_data = {};
    }

    // 5. mitigation_control: Mantiene solo lo SKU e i controlli di mitigazione con i relativi dettagli
    if (Array.isArray(original.mitigation_control)) {
        safeData.mitigation_control = original.mitigation_control.map(mit => {
            if (!mit) return null;
            return {
                service_sku: mit.service_sku,
                controlli_mitigazione: mit.controlli_mitigazione || [],
                operatori_coinvolti: mit.operatori_coinvolti || [],
                attrezzature_coinvolte: mit.attrezzature_coinvolte || []
            };
        }).filter(Boolean);
    } else {
        safeData.mitigation_control = [];
    }

    // 6. checklist_state: Mantiene solo le risposte, calcoli di rischio e la data dell'ultimo svolgimento
    let rawState = original.checklist_state || original.risk || original.saved_checklists || [];
    if (Array.isArray(rawState)) {
        safeData.checklist_state = rawState.map(st => {
            if (!st) return null;
            const cleanSt = {
                service_sku: st.service_sku,
                D: st.D,
                C: st.C,
                P: st.P,
                R: st.R,
                overall_justification: st.overall_justification || '',
                last_executed: st.last_executed || null,
                answers: {}
            };
            if (st.answers) {
                Object.keys(st.answers).forEach(qId => {
                    const ans = st.answers[qId] || {};
                    cleanSt.answers[qId] = {
                        checked: ans.checked === true,
                        label: ans.label || '',
                        description: ans.description || '',
                        executed_at: ans.executed_at || null
                    };
                });
            }
            return cleanSt;
        }).filter(Boolean);
    } else {
        safeData.checklist_state = [];
    }

    sanitizedOutput.push({ json: safeData });
}

return sanitizedOutput;
